text:
/* Educator profile grid spacing */
.grid {
  gap: 2rem;
  margin-bottom: 2rem;
}

/* Educator photo alignment */
.g-col-4 img {
  display: block;
  margin: 0 auto 1rem auto;
}

.g-col-4 {
  text-align: center;
}

/* Button styling */
.btn {
  margin-right: 0.5rem;
  margin-bottom: 0.5rem;
}

/* PDF iframe */
iframe {
  margin-bottom: 1rem;
}

/* Workshop listing table */
.listing-table {
  font-size: 0.95rem;
}
